+    let slen = bytes.len();
+    if slen == 0 || slen > 20 {
+        return Err(StoreError::ValueNotInteger);
+    }
+    if slen == 1 && bytes[0] == b'0' {
+        return Ok(0);
+    }
+
+    let mut p = 0;
+    let negative = bytes[0] == b'-';
+    if negative {
+        p += 1;
+        if p == slen {
+            return Err(StoreError::ValueNotInteger);
+        }
+    }
+
+    if bytes[p] >= b'1' && bytes[p] <= b'9' {
+        let mut v: u64 = (bytes[p] - b'0') as u64;
+        p += 1;
+        while p < slen {
+            let b = bytes[p];
+            if b.is_ascii_digit() {
+                if v > (u64::MAX / 10) {
+                    return Err(StoreError::ValueNotInteger);
+                }
+                v *= 10;
+                let digit = (b - b'0') as u64;
+                if v > (u64::MAX - digit) {
+                    return Err(StoreError::ValueNotInteger);
+                }
+                v += digit;
+                p += 1;
+            } else {
+                return Err(StoreError::ValueNotInteger);
+            }
+        }
+
+        if negative {
+            let limit = (i64::MIN as u64).wrapping_neg();
+            if v > limit {
+                return Err(StoreError::ValueNotInteger);
+            }
+            return Ok(v.wrapping_neg() as i64);
+        } else {
+            if v > i64::MAX as u64 {
+                return Err(StoreError::ValueNotInteger);
+            }
+            return Ok(v as i64);
+        }
+    }
+
+    Err(StoreError::ValueNotInteger)
